import React, { useEffect, useRef, useState } from 'react';
import '../styles/GameCanvas.css';

// --- Where your JSON manifest is stored ---
const MANIFEST_URL = 'https://your-bucket.s3.amazonaws.com/iconsManifest.json';

// Adjust these as needed:
const S3_BUCKET_URL = 'https://hackthon-backend-files-ep-2024.s3.amazonaws.com';
const ICONS_BASE_PATH = '/amazon-icons-set/Architecture-Service-Icons_06072024';
const S3_ROCKET_PATH = `${S3_BUCKET_URL}/games/rocket`;
const FIREBALL_PATH = `${S3_BUCKET_URL}/games/bullet/fireball.png`;

const GameCanvas = () => {
  // -------------------- State --------------------
  const [timeLeft, setTimeLeft] = useState(60);
  const [score, setScore] = useState(0);
  const [currentInstructionIndex, setCurrentInstructionIndex] = useState(0);
  const [selectedRocket, setSelectedRocket] = useState(() => {
    return localStorage.getItem('selectedRocket') || null;
  });
  const [showNameModal, setShowNameModal] = useState(true);
  const [tempPlayerName, setTempPlayerName] = useState('');
  const [nameError, setNameError] = useState('');
  const [playerName, setPlayerName] = useState(() => {
    return localStorage.getItem('playerName') || '';
  });
  const [gameOver, setGameOver] = useState(false);
  const [gameOverHandled, setGameOverHandled] = useState(false);
  const [gameStarted, setGameStarted] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [highScores, setHighScores] = useState(() => {
    const saved = localStorage.getItem('highScores');
    return saved ? JSON.parse(saved) : [];
  });
  const [cheerMessage, setCheerMessage] = useState('');
  const [showCheerMessage, setShowCheerMessage] = useState(false);
  const [soundsLoaded, setSoundsLoaded] = useState(false);
  const [showRocketModal, setShowRocketModal] = useState(true);

  // -------------------- Game Data from Manifest --------------------
  const [iconsData, setIconsData] = useState([]); // all icons from JSON
  const [instructions, setInstructions] = useState([]); // we’ll build this from discovered categories
  const [manifestLoaded, setManifestLoaded] = useState(false);

  // Refs
  const canvasRef = useRef(null);
  const iconsRef = useRef([]);
  const bulletsRef = useRef([]);
  const feedbacksRef = useRef([]);
  const rocketImage = useRef(new Image());
  const gunRef = useRef({ x: 400 - 25, y: 800 - 100, width: 120, height: 120 });
  const particlesRef = useRef([]);
  const sounds = useRef({});

  const fireballImage = new Image();
  fireballImage.src = FIREBALL_PATH;

  // ---------- 1) Fetch the Manifest at startup ----------
  useEffect(() => {
    async function fetchIconsManifest() {
      try {
        const response = await fetch(MANIFEST_URL);
        if (!response.ok) {
          console.warn('Failed to fetch icons manifest:', response.statusText);
          return;
        }
        const data = await response.json();
        // data is an array like [ {path, serviceName}, ... ]

        // parse out "Arch_Compute" from the path to get "Compute"
        const fullData = data.map((item) => {
          // example path:
          // "amazon-icons-set/Architecture-Service-Icons_06072024/Arch_Compute/Amazon-EC2.svg"
          // We want to parse out "Compute" from "Arch_Compute"
          // using a simple regex or split:
          const match = item.path.match(/Arch_(\w+)/i); // captures word after Arch_
          let category = 'Unknown';
          if (match && match[1]) {
            category = match[1]; // e.g. "Compute"
          }
          return {
            ...item,
            category, // store computed category
          };
        });

        setIconsData(fullData);
        setManifestLoaded(true);
      } catch (err) {
        console.error('Error fetching icons manifest:', err);
      }
    }
    fetchIconsManifest();
  }, []);

  // ---------- 2) Build random instructions from discovered categories ----------
  useEffect(() => {
    if (!manifestLoaded || iconsData.length === 0) return;

    // get unique categories from iconsData
    const categoriesSet = new Set(iconsData.map((i) => i.category));
    const categoriesArray = Array.from(categoriesSet);

    // shuffle them, or pick how many missions you want
    const shuffled = [...categoriesArray].sort(() => 0.5 - Math.random());
    const pickCount = Math.min(2, shuffled.length); // for example, pick 2
    const chosen = shuffled.slice(0, pickCount);

    // build instructions
    const newInstructions = chosen.map((cat) => ({
      text: `Shoot the ${cat} icons!`,
      category: cat,
      displayName: cat,
    }));
    setInstructions(newInstructions);
  }, [manifestLoaded, iconsData]);

  // ---------- Preload rocket image when selected ----------
  useEffect(() => {
    if (selectedRocket) {
      rocketImage.current.src = selectedRocket;
    }
  }, [selectedRocket]);

  // ---------- Timer ----------
  useEffect(() => {
    if (gameStarted && !gameOver && timeLeft > 0) {
      const timer = setInterval(() => setTimeLeft((prev) => prev - 1), 1000);
      return () => clearInterval(timer);
    } else if (timeLeft === 0 && !gameOverHandled) {
      handleGameOver();
    }
  }, [timeLeft, gameOver, gameOverHandled, gameStarted]);

  // ---------- Sounds ----------
  useEffect(() => {
    const soundFiles = {
      shoot: `${S3_BUCKET_URL}/games/sounds/pistol_sound.mp3`,
      correct: `${S3_BUCKET_URL}/games/sounds/correct_sound.mp3`,
      incorrect: `${S3_BUCKET_URL}/games/sounds/incorrect_sound.mp3`,
      levelup: `${S3_BUCKET_URL}/games/sounds/levelup.mp3`,
    };

    const createSafeAudio = (path) => {
      const audio = new Audio();
      return new Promise((resolve) => {
        audio.addEventListener('error', () => {
          console.warn(`Sound file not found: ${path}`);
          resolve(null);
        });
        audio.addEventListener('canplaythrough', () => {
          resolve(audio);
        });
        setTimeout(() => resolve(null), 2000);
        audio.src = path;
      });
    };

    async function loadSounds() {
      const loaded = {};
      for (const [key, path] of Object.entries(soundFiles)) {
        loaded[key] = await createSafeAudio(path);
      }
      sounds.current = loaded;
      setSoundsLoaded(true);
    }
    loadSounds();

    return () => {
      Object.values(sounds.current).forEach((s) => {
        if (s) {
          s.pause();
          s.src = '';
        }
      });
    };
  }, []);

  const toggleMute = () => {
    setIsMuted((prev) => !prev);
    Object.values(sounds.current).forEach((s) => {
      if (s) s.muted = !isMuted;
    });
  };

  const playSound = (soundName) => {
    const snd = sounds.current[soundName];
    if (snd && !isMuted) {
      try {
        snd.currentTime = 0;
        snd.volume = 0.3;
        snd.play().catch((err) => console.warn(`Error playing ${soundName}:`, err));
      } catch (err) {
        console.warn(`Error with sound ${soundName}:`, err);
      }
    }
  };

  // ---------- Particles ----------
  class Particle {
    constructor(x, y, color) {
      this.x = x;
      this.y = y;
      this.color = color;
      this.size = Math.random() * 3 + 2;
      this.speedX = Math.random() * 6 - 3;
      this.speedY = Math.random() * 6 - 3;
      this.lifetime = 1;
      this.initialSize = this.size;
    }
    update() {
      this.x += this.speedX;
      this.y += this.speedY;
      this.lifetime -= 0.02;
      this.size = Math.max(0, this.initialSize * this.lifetime);
    }
    draw(ctx) {
      if (this.size <= 0) return;
      ctx.fillStyle = this.color;
      ctx.globalAlpha = this.lifetime;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }
  }

  const createExplosion = (x, y, color) => {
    for (let i = 0; i < 20; i++) {
      particlesRef.current.push(new Particle(x, y, color));
    }
  };

  // ---------- Load icons for mission ----------
  const loadIconsForMission = (index) => {
    iconsRef.current = [];
    if (!instructions[index]) {
      console.warn('No instruction at index:', index);
      return;
    }
    const currentCategory = instructions[index].category;
    console.log(`Loading icons for category: ${currentCategory}`);

    // 1) All icons for currentCategory
    const categoryIcons = iconsData.filter((item) => item.category === currentCategory);
    // 2) All icons for other categories
    const otherIcons = iconsData.filter((item) => item.category !== currentCategory);

    // pick 4 from the category
    let selectedCategoryIcons = [];
    if (categoryIcons.length <= 4) {
      while (selectedCategoryIcons.length < 4) {
        selectedCategoryIcons.push(
          ...categoryIcons.slice(0, 4 - selectedCategoryIcons.length)
        );
      }
    } else {
      const shuffled = [...categoryIcons].sort(() => 0.5 - Math.random());
      selectedCategoryIcons = shuffled.slice(0, 4);
    }

    // pick 6 from other categories
    const chosenOthers = [];
    const usedCats = new Set();
    // Group otherIcons by category
    const catMap = {};
    otherIcons.forEach((o) => {
      if (!catMap[o.category]) catMap[o.category] = [];
      catMap[o.category].push(o);
    });
    const catKeys = Object.keys(catMap).sort(() => 0.5 - Math.random());
    for (let i = 0; i < catKeys.length && chosenOthers.length < 6; i++) {
      const cat = catKeys[i];
      if (usedCats.has(cat)) continue;
      const arr = catMap[cat];
      if (arr.length > 0) {
        const rndIdx = Math.floor(Math.random() * arr.length);
        chosenOthers.push(arr[rndIdx]);
        usedCats.add(cat);
      }
    }
    if (chosenOthers.length < 6) {
      const remain = otherIcons.filter((o) => !chosenOthers.includes(o));
      const shuffled = remain.sort(() => 0.5 - Math.random());
      chosenOthers.push(...shuffled.slice(0, 6 - chosenOthers.length));
    }

    // Log for debugging
    console.log(
      `Category icons: ${selectedCategoryIcons.map((c) => c.serviceName).join(', ')}`
    );
    console.log(
      `Distractions: ${chosenOthers.map((c) => c.serviceName + ' (' + c.category + ')').join(', ')}`
    );

    // Put them into iconsRef
    const canvas = canvasRef.current;
    const positions = [];
    const getRandomX = () => Math.floor(Math.random() * (canvas.width - 50));

    const addIcons = (arr, isCategory) => {
      arr.forEach((item) => {
        let x = getRandomX();
        while (positions.some((p) => Math.abs(p - x) < 50)) {
          x = getRandomX();
        }
        positions.push(x);

        const img = new Image();
        img.src = `${S3_BUCKET_URL}/${item.path}`; // or item.path if it’s a full URL
        iconsRef.current.push({
          x,
          y: -50,
          type: item.category,
          name: item.serviceName,
          image: img,
          hit: false,
        });
      });
    };

    addIcons(selectedCategoryIcons, true);
    addIcons(chosenOthers, false);
  };

  // ---------- Next mission ----------
  const NewCategoryMission = () => {
    setCurrentInstructionIndex((prev) => (prev + 1) % instructions.length);
    playSound('levelup');
  };

  // ---------- Collisions ----------
  const showFeedback = (x, y, isCorrect, points, iconName) => {
    feedbacksRef.current.push({ x, y, isCorrect, points, name: iconName, time: Date.now() });
  };

  const checkCollisions = () => {
    const canvas = canvasRef.current;
    const currentCategory = instructions[currentInstructionIndex]?.category || '';

    bulletsRef.current = bulletsRef.current.filter((bullet) => {
      let hitSomething = false;
      for (let i = 0; i < iconsRef.current.length; i++) {
        const icon = iconsRef.current[i];
        if (
          !icon.hit &&
          bullet.x > icon.x &&
          bullet.x < icon.x + 50 &&
          bullet.y > icon.y &&
          bullet.y < icon.y + 50
        ) {
          icon.hit = true;
          hitSomething = true;
          if (icon.type === currentCategory) {
            const heightPct = 1 - icon.y / canvas.height;
            const heightBonus = Math.floor(heightPct * 20);
            const points = 5 + heightBonus;
            setScore((prev) => {
              const top = highScores.length ? Math.max(...highScores.map((s) => s.score)) : 0;
              if (prev + points > top) {
                showCheerleaderMessage('highScore');
              } else if (heightBonus > 15) {
                showCheerleaderMessage('goodShot');
              }
              return prev + points;
            });
            showFeedback(icon.x, icon.y, true, points, icon.name);
            playSound('correct');
            createExplosion(icon.x + 25, icon.y + 25, '#4CAF50');
          } else {
            setScore((prev) => prev - 5);
            showFeedback(icon.x, icon.y, false, -5, icon.name);
            playSound('incorrect');
          }
          break; // stop scanning icons
        }
      }
      return !hitSomething; // keep bullet if it didn't hit anything
    });

    iconsRef.current = iconsRef.current.filter((icon) => !icon.hit);

    if (iconsRef.current.length === 0 && timeLeft > 0) {
      NewCategoryMission();
    }
  };

  // ---------- Main game loop ----------
  const gameLoop = () => {
    if (!gameStarted || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // draw rocket
    const { x, y, width, height } = gunRef.current;
    ctx.drawImage(rocketImage.current, x, y, width, height);

    // draw icons
    iconsRef.current.forEach((icon) => {
      if (!icon.hit) {
        ctx.save();
        const radius = 10;
        ctx.beginPath();
        ctx.moveTo(icon.x + radius, icon.y);
        ctx.lineTo(icon.x + 50 - radius, icon.y);
        ctx.quadraticCurveTo(icon.x + 50, icon.y, icon.x + 50, icon.y + radius);
        ctx.lineTo(icon.x + 50, icon.y + 50 - radius);
        ctx.quadraticCurveTo(icon.x + 50, icon.y + 50, icon.x + 50 - radius, icon.y + 50);
        ctx.lineTo(icon.x + radius, icon.y + 50);
        ctx.quadraticCurveTo(icon.x, icon.y + 50, icon.x, icon.y + 50 - radius);
        ctx.lineTo(icon.x, icon.y + radius);
        ctx.quadraticCurveTo(icon.x, icon.y, icon.x + radius, icon.y);
        ctx.closePath();
        ctx.clip();

        ctx.drawImage(icon.image, icon.x, icon.y, 50, 50);
        ctx.restore();
        icon.y += 0.7;
      }
    });

    // remove off-screen
    iconsRef.current = iconsRef.current.filter((i) => i.y < canvas.height);

    // draw bullets
    bulletsRef.current.forEach((b) => {
      ctx.drawImage(fireballImage, b.x, b.y, 20, 20);
      b.y -= 5;
    });
    bulletsRef.current = bulletsRef.current.filter((b) => b.y > 0);

    // draw feedback
    const now = Date.now();
    feedbacksRef.current = feedbacksRef.current.filter((f) => {
      const elapsed = now - f.time;
      if (elapsed < 3000) {
        ctx.shadowColor = 'rgba(0,0,0,0.5)';
        ctx.shadowBlur = 4;
        ctx.fillStyle = f.isCorrect ? '#4CAF50' : '#F44336';
        ctx.font = 'bold 28px Arial';
        const pts = f.points > 0 ? `+${f.points}` : `${f.points}`;
        ctx.fillText(pts, f.x + 10, f.y - 20);

        ctx.font = '16px Arial';
        ctx.fillText(f.name, f.x + 60, f.y + 25);

        ctx.font = 'bold 55px Arial';
        ctx.fillText(f.isCorrect ? '✔' : '✘', f.x + 10, f.y + 30);

        ctx.shadowBlur = 0;
        return true;
      }
      return false;
    });

    // draw particles
    particlesRef.current = particlesRef.current.filter((p) => {
      if (p.lifetime > 0 && p.size > 0) {
        p.update();
        p.draw(ctx);
        return true;
      }
      return false;
    });

    checkCollisions();

    requestAnimationFrame(gameLoop);
  };

  // ---------- Encouragement messages ----------
  const cheerleaderMessages = {
    goodShot: [
      "Great shot! You're an AWS Pro! 🌟",
      "Amazing cloud skills! Keep it up! 🎯",
      "You're on fire in the cloud! 🔥",
      "That's how AWS experts do it! 👏",
    ],
    highScore: [
      "New high score! You're going serverless! 🏆",
      "You're breaking cloud records! 🎖️",
      "Legendary AWS performance! 👑",
    ],
    timeWarning: [
      "30 seconds left - you're highly available! ⏰",
      "Time for the final deployment! 💪",
      "Make every compute unit count! ⭐",
    ],
    encouragement: [
      "You've got this, cloud warrior! 🚀",
      "Keep going! You're AWS certified material! 🌟",
      "I believe in your cloud powers! 💫",
      "Show them your AWS expertise! 💪",
    ],
  };

  const showCheerleaderMessage = (type) => {
    const arr = cheerleaderMessages[type];
    if (!arr) return;
    const msg = arr[Math.floor(Math.random() * arr.length)];
    setCheerMessage(msg);
    setShowCheerMessage(true);
    setTimeout(() => setShowCheerMessage(false), 3000);
  };

  // random encouragement
  useEffect(() => {
    const interval = setInterval(() => {
      if (timeLeft > 0 && Math.random() < 0.3) {
        showCheerleaderMessage('encouragement');
      }
    }, 10000);
    return () => clearInterval(interval);
  }, [timeLeft]);

  // 30s warning
  useEffect(() => {
    if (timeLeft === 30) showCheerleaderMessage('timeWarning');
  }, [timeLeft]);

  // ---------- Game Over ----------
  const handleGameOver = () => {
    if (gameOverHandled) return;
    setGameOver(true);
    setGameOverHandled(true);

    const newScore = { name: playerName, score };
    const sorted = [...highScores, newScore].sort((a, b) => b.score - a.score);
    const top5 = sorted.slice(0, 5);
    setHighScores(top5);
    localStorage.setItem('highScores', JSON.stringify(top5));
  };

  // ---------- Initialize canvas & start loop ----------
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      canvas.width = 1200;
      canvas.height = 800;
      const ctx = canvas.getContext('2d');
      ctx.imageSmoothingEnabled = true;

      if (gameStarted) {
        requestAnimationFrame(gameLoop);
      }
    }
  }, [gameStarted]);

  // ---------- Mouse events ----------
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      let newX = e.clientX - rect.left - gunRef.current.width / 2;
      newX = Math.max(-30, Math.min(newX, canvas.width - gunRef.current.width + 30));
      gunRef.current.x = newX;
    };
    const handleClick = () => {
      if (gameStarted && timeLeft > 0) {
        playSound('shoot');
        bulletsRef.current.push({
          x: gunRef.current.x + gunRef.current.width / 2 - 10,
          y: gunRef.current.y - 20,
        });
      }
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('click', handleClick);
    return () => {
      canvas.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('click', handleClick);
    };
  }, [gameStarted]);

  // Clear local storage if you always want fresh data each load
  useEffect(() => {
    localStorage.removeItem('playerName');
    localStorage.removeItem('selectedRocket');
  }, []);

  // ---------- Name Modal ----------
  const handleNameSubmit = (e) => {
    e.preventDefault();
    if (tempPlayerName.trim().length < 2) {
      setNameError('Name must be at least 2 characters long');
      return;
    }
    if (tempPlayerName.trim().length > 15) {
      setNameError('Name must be less than 15 characters');
      return;
    }
    const cleaned = tempPlayerName.trim();
    setPlayerName(cleaned);
    localStorage.setItem('playerName', cleaned);
    setShowNameModal(false);
  };

  // ---------- Rocket Modal ----------
  const rocketOptions = [
    { id: `${S3_ROCKET_PATH}/rocket1.png`, name: 'Modern Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket2.png`, name: 'Power Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket3.png`, name: 'Stealth Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket4.png`, name: 'Classic Rocket' },
  ];

  const handleRocketSelect = (rocketId) => {
    setSelectedRocket(rocketId);
    localStorage.setItem('selectedRocket', rocketId);
    rocketImage.current.src = rocketId;
    setShowRocketModal(false);
    setGameStarted(true);

    // Once game starts, load the FIRST mission’s icons
    if (instructions.length > 0) {
      loadIconsForMission(currentInstructionIndex);
    } else {
      console.warn('No instructions yet—maybe the manifest hasn’t loaded?');
    }
  };

  // ---------- Watch currentInstructionIndex to load next mission ----------
  useEffect(() => {
    if (!gameStarted) return;
    if (currentInstructionIndex < instructions.length) {
      console.log('Switching to mission index:', currentInstructionIndex);
      loadIconsForMission(currentInstructionIndex);
    }
  }, [currentInstructionIndex, gameStarted]);

  // ---------- Render ----------
  return (
    <div className="gameCanvas-container">
      <h1 className="gameCanvas-game-title">AWS Cloud Shooter</h1>
      <div className="gameCanvas-game-content">
        <div className="gameCanvas-canvas-wrapper">
          <canvas ref={canvasRef} className="gameCanvas-game-canvas" />
        </div>

        <div className="gameCanvas-instruction-panel">
          <div className="gameCanvas-player-info">
            <div className="gameCanvas-player-name">Player: {playerName}</div>
            <div className="gameCanvas-score-display">
              <span role="img" aria-label="alien">
                👾
              </span>{' '}
              Score: {score}{' '}
              <span role="img" aria-label="joystick">
                🕹️
              </span>
              {soundsLoaded && Object.values(sounds.current).some((s) => s) && (
                <button
                  className="gameCanvas-sound-toggle"
                  onClick={toggleMute}
                  aria-label="Toggle sound"
                >
                  {isMuted ? '🔇' : '🔊'}
                </button>
              )}
            </div>
          </div>

          <div className="gameCanvas-timer-display">Time: {timeLeft}s</div>

          <div className="gameCanvas-score-explanation">
            <h4>How to Score:</h4>
            <ul>
              <li>• Hit correct icon: +5 points</li>
              <li>• Height bonus: up to +20</li>
              <li>• Wrong hit: -5 points</li>
              <li>• Tip: Shoot icons as high as possible!</li>
            </ul>
          </div>

          <div className="gameCanvas-high-scores">
            <h4>High Scores</h4>
            <ul>
              {highScores.map((entry, i) => (
                <li key={i}>
                  <span className="gameCanvas-high-score-name">{entry.name}:</span> {entry.score}
                </li>
              ))}
            </ul>
          </div>

          <div className="gameCanvas-mission-container">
            <h3 className="gameCanvas-mission-title">Current Mission</h3>
            <div className="gameCanvas-mission-text">
              {instructions[currentInstructionIndex]
                ? instructions[currentInstructionIndex].text
                : 'No mission loaded'}
            </div>
          </div>
        </div>
      </div>

      {showRocketModal && (
        <div className="gameCanvas-modal-overlay">
          <div className="gameCanvas-rocket-selection-modal">
            <h2>Choose Your Rocket</h2>
            <div className="gameCanvas-rocket-grid">
              {rocketOptions.map((rocket) => (
                <div
                  key={rocket.id}
                  className={`gameCanvas-rocket-option ${
                    selectedRocket === rocket.id ? 'selected' : ''
                  }`}
                  onClick={() => handleRocketSelect(rocket.id)}
                >
                  <img src={rocket.id} alt={rocket.name} />
                  <p>{rocket.name}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {gameOver && (
        <div className="gameCanvas-game-over">
          <h3>Game Over!</h3>
          <button onClick={() => window.location.reload()}>Play Again</button>
        </div>
      )}

      {showCheerMessage && (
        <div className="gameCanvas-cheerleader-container">
          <div className="gameCanvas-cheerleader-character">
            <img src={`${S3_BUCKET_URL}/games/utilities/cheerleader.png`} alt="Cheerleader" />
          </div>
          <div className="gameCanvas-cheer-message">{cheerMessage}</div>
        </div>
      )}

      {showNameModal && (
        <div className="gameCanvas-modal-overlay">
          <div className="gameCanvas-modal">
            <h2>Welcome to AWS Cloud Shooter!</h2>
            <p>Enter your name to start the game:</p>
            <form onSubmit={handleNameSubmit}>
              <input
                type="text"
                value={tempPlayerName}
                onChange={(e) => {
                  setTempPlayerName(e.target.value);
                  setNameError('');
                }}
                placeholder="Your name"
                className="gameCanvas-name-input"
                autoFocus
              />
              {nameError && <div className="gameCanvas-name-error">{nameError}</div>}
              <button type="submit" className="gameCanvas-start-button">
                Start Game
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameCanvas;
